arguments.command:
cd /workspace && awk '
BEGIN { depth = 0 }
{
  line = $0
  opens = gsub(/\(/, "(", line)
  closes = gsub(/\)/, ")", line)
  net = opens - closes
  if (depth > 0 && depth + net == 0) {
    printf "Line %d: depth goes %d -> 0~n", NR, depth
  }
  depth += net
}' /workspace/T2.rkt

cd /workspace && awk '
BEGIN { depth = 0 }
{
  line = $0
  opens = gsub(/\(/, "(", line)
  closes = gsub(/\)/, ")", line)
  net = opens - closes
  if (depth + net < 0) {
    printf "Line %d: negative depth %d~n", NR, depth + net
  }
  depth += net
}' /workspace/T2.rkt

cd /workspace && awk '
BEGIN { depth = 0 }
{
  line = $0
  opens = gsub(/\(/, "(", line)
  closes = gsub(/\)/, ")", line)
  net = opens - closes
  printf "Line %d: opens=%d closes=%d depth=%d->%d~n", NR, opens, closes, depth, depth + net
  depth += net
}' /workspace/T2.rkt | tail -100
